---
import type { HTMLAttributes } from "astro/types"
import type { Align, Position, Side } from "@data-slot/select"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  defaultValue?: string
  placeholder?: string
  disabled?: boolean
  required?: boolean
  name?: string
  position?: Position
  side?: Side
  align?: Align
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
  highlightItemOnHover?: boolean
}

const {
  class: className,
  defaultValue,
  placeholder,
  disabled,
  required,
  name,
  position,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  highlightItemOnHover,
  ...props
} = Astro.props
---

<div
  data-slot="select"
  data-default-value={defaultValue}
  data-placeholder={placeholder}
  data-disabled={disabled}
  data-required={required}
  data-name={name}
  data-position={position}
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-avoid-collisions={avoidCollisions}
  data-collision-padding={collisionPadding}
  data-highlight-item-on-hover={highlightItemOnHover}
  class={cn(
    "group/select relative inline-flex w-fit flex-col gap-1.5",
    className
  )}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/select"

  const initSelect = () => {
    create()
  }

  initSelect()

  document.addEventListener("astro:page-load", initSelect)
</script>

---
import type { HTMLAttributes } from "astro/types"
import ChevronDownIcon from "lucide-static/icons/chevron-down.svg"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"button"> & {
  size?: "sm" | "default"
  showIcon?: boolean
}

const {
  class: className,
  type = "button",
  size = "default",
  showIcon = true,
  ...props
} = Astro.props
---

<button
  data-slot="select-trigger"
  data-size={size}
  type={type}
  class={cn(
    "border-input dark:bg-input/30 dark:hover:bg-input/50 focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:aria-invalid:border-destructive/50 data-placeholder:text-muted-foreground flex w-full items-center justify-between gap-1.5 rounded-md border bg-transparent py-2 pr-2 pl-2.5 text-sm whitespace-nowrap shadow-xs transition-[color,box-shadow] outline-none focus-visible:ring-3 disabled:cursor-not-allowed disabled:opacity-50 data-[size=default]:h-9 data-[size=sm]:h-8 *:data-[slot=select-value]:line-clamp-1 *:data-[slot=select-value]:flex *:data-[slot=select-value]:items-center *:data-[slot=select-value]:gap-1.5 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
    className
  )}
  {...props}
>
  <slot />
  {
    showIcon && (
      <ChevronDownIcon class="text-muted-foreground pointer-events-none size-4" />
    )
  }
</button>

---
import type { HTMLAttributes } from "astro/types"
import type { Align, Position, Side } from "@data-slot/select"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  position?: Position
  side?: Side
  align?: Align
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
}

const {
  class: className,
  hidden = true,
  position,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  ...props
} = Astro.props
---

<div data-slot="select-portal">
  <div
    data-slot="select-positioner"
    data-position={position}
    data-side={side}
    data-align={align}
    data-side-offset={sideOffset}
    data-align-offset={alignOffset}
    data-avoid-collisions={avoidCollisions}
    data-collision-padding={collisionPadding}
    class="isolate z-50"
  >
    <div
      data-slot="select-content"
      data-position={position}
      data-align-trigger={position === "item-aligned" ? "true" : undefined}
      data-side={side}
      data-align={align}
      data-side-offset={sideOffset}
      data-align-offset={alignOffset}
      data-avoid-collisions={avoidCollisions}
      data-collision-padding={collisionPadding}
      hidden={hidden}
      class={cn(
        "bg-popover text-popover-foreground ring-foreground/10 data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95 relative isolate z-50 max-h-(--available-height) w-(--anchor-width) min-w-36 origin-(--transform-origin) overflow-x-hidden overflow-y-auto rounded-md shadow-md ring-1 duration-100 outline-none data-[align-trigger=true]:animate-none",
        className
      )}
      {...props}
    >
      <div
        data-slot="select-viewport"
        data-position={position}
        class="p-1 data-[position=item-aligned]:w-full data-[position=popper]:min-w-36"
      >
        <slot />
      </div>
    </div>
  </div>
</div>
